  if (root == nullptr) return root;

  if (key < root->data) {
    root->left = Delete(root->left, key);
  } else if (key > root->data) {
    root->right = Delete(root->right, key);
  } else {
    if ((root->left == nullptr) || (root->right == nullptr)) {
