      Node* parent = root->parent;

      if (temp != nullptr) {
        temp->parent = parent;
      }

      if (parent) {
        if (parent->left == root) {
          parent->left = temp;
        } else {
          parent->right = temp;
        }
      } else {
        // Update the top if the root node is being deleted with one or no child
        top = temp;
