```cpp
class Solution {
public:
  int mySqrt(int x) {
    if (x < 2) return x; // Handle the edge cases 0 and 1 directly

    long min = 0; // Use long to prevent int overflow
    long max = x / 2 + 1; // Set the upper bound to x/2+1 which will be sufficient to find the sqrt(x)

    while (min <= max) {
      long mid = min + (max - min) / 2; // Correct mid calculation
      long sqar = mid * mid; // Square of mid as a long to prevent overflow
      if (sqar == x) {
        return mid; // Perfect square, return result
      } else if (sqar < x) {
        min = mid + 1; // Move the lower bound up
      } else {
        max = mid - 1; // Move the upper bound down
      }
    }

    return max; // Return the floor value of the square root
  }
};
```

This code now accounts for the proper middle index during the binary search, correctly iterates to find the square root, uses `long` to avoid integer overflow, handles edge cases, and ensures returning the integer part of the square root of `x`.

